import React from 'react';
import { Users } from 'lucide-react';

export default function LiveCounter() {
  return (
    <div className="flex flex-col items-center justify-center py-10 border-y border-luxury-gold/10 my-10" data-aos="zoom-in">
      <div className="bg-luxury-gold/10 p-4 rounded-full mb-4">
        <Users className="text-luxury-gold" size={32} />
      </div>
      <h4 className="text-3xl font-serif italic text-luxury-dark">128+ Guests</h4>
      <p className="text-[10px] uppercase tracking-[0.3em] text-gray-400 mt-2">Joining the Celebration</p>
    </div>
  );
}
